import sys
import time
import threading
from itertools import cycle
from config import Colors  # not used but kept for compatibility

class colors:
    SKY_BLUE = "\033[38;5;117m"
    SKY = "\033[38;5;117m"
    WHITE = "\033[97m"
    GOLD = "\033[38;5;220m"
    CYAN = "\033[96m"
    GREEN = "\033[92m"
    RED = "\033[91m"
    YELLOW = "\033[93m"
    MAGENTA = "\033[95m"
    RESET = "\033[0m"
    BOLD = "\033[1m"
    DIM = "\033[2m"

# ==========================================
# TYPING ANIMATIONS
# ==========================================

def type_animation(text, delay=0.05, color=colors.WHITE):
    """Display text with typing animation"""
    print(color, end='')
    for char in text:
        sys.stdout.write(char)
        sys.stdout.flush()
        time.sleep(delay)
    print(colors.RESET)

def type_animation_slow(text, delay=0.08, color=colors.WHITE):
    """Slow typing animation for important messages"""
    print(color, end='')
    for char in text:
        sys.stdout.write(char)
        sys.stdout.flush()
        time.sleep(delay)
    print(colors.RESET)

def type_animation_fast(text, delay=0.02, color=colors.WHITE):
    """Fast typing animation for quick messages"""
    print(color, end='')
    for char in text:
        sys.stdout.write(char)
        sys.stdout.flush()
        time.sleep(delay)
    print(colors.RESET)

# ==========================================
# LOADING BAR (npm install style)
# ==========================================

def loading_bar(text="Loading", duration=3, color=colors.SKY_BLUE, bar_length=30):
    """Loading bar animation like npm install"""
    print(color, end='')
    for i in range(bar_length + 1):
        percent = int((i / bar_length) * 100)
        filled = '█' * i
        empty = '░' * (bar_length - i)
        sys.stdout.write(f'\r{text} [{filled}{empty}] {percent}%')
        sys.stdout.flush()
        time.sleep(duration / bar_length)
    print(colors.RESET)

# ==========================================
# ENHANCED LOADING: Spinner + Progress Bar + Percentage
# (npm-style package installation effect)
# ==========================================

def type_loading(message="Installing packages", duration=3, color=colors.SKY_BLUE):
    """
    Display an animated loading bar similar to npm install.
    Combines spinner, progress bar and percentage.
    Usage: type_loading(message="Verifying details", duration=2)
    """
    terminal_width = 80  # safe default
    try:
        import shutil
        terminal_width = shutil.get_terminal_size().columns
    except:
        pass

    bar_width = min(40, terminal_width - 40)
    spinner = cycle(["⠋", "⠙", "⠹", "⠸", "⠼", "⠴", "⠦", "⠧", "⠇", "⠏"])
    start_time = time.time()

    stop_event = threading.Event()

    def _animate():
        while not stop_event.is_set():
            elapsed = time.time() - start_time
            progress = min(elapsed / duration, 1.0)
            percent = int(progress * 100)
            filled = int(bar_width * progress)
            bar = "█" * filled + "░" * (bar_width - filled)

            spin = next(spinner)
            line = f"\r{color}{spin} {message} [{bar}] {percent}%{colors.RESET}"
            sys.stdout.write(line.ljust(terminal_width))
            sys.stdout.flush()
            time.sleep(0.08)

    t = threading.Thread(target=_animate, daemon=True)
    t.start()

    time.sleep(duration)
    stop_event.set()
    t.join(timeout=0.2)

    # Clear line and print checkmark
    sys.stdout.write("\r" + " " * terminal_width + "\r")
    print(f"✔ {message} completed successfully.\n")

# ==========================================
# LOADING SPINNER (original simple spinner kept for compatibility)
# ==========================================

def spinner_loading(text, duration=2):
    """Simple spinner loading (legacy)"""
    chars = ['⠋', '⠙', '⠹', '⠸', '⠼', '⠴', '⠦', '⠧', '⠇', '⠏']
    duration = int(duration)
    for i in range(duration * 10):
        sys.stdout.write(f'\r{text} {colors.SKY_BLUE}{chars[i % len(chars)]}{colors.RESET}')
        sys.stdout.flush()
        time.sleep(0.1)
    print()

# ==========================================
# PULSE LOADING
# ==========================================

def pulse_loading(text="Processing", duration=3, color=colors.SKY_BLUE):
    """Pulse loading animation - text fades in and out"""
    dots = ['.', '..', '...', '....', '...', '..', '.']
    steps = int(duration / 0.3) if duration > 0 else len(dots)
    for i in range(steps):
        dot_idx = i % len(dots)
        sys.stdout.write(f'\r{color}{text}{dots[dot_idx]}{colors.RESET}')
        sys.stdout.flush()
        time.sleep(0.3)
    print()

# ==========================================
# RAINBOW LOADING
# ==========================================

def rainbow_loading(text="Loading", duration=3):
    """Rainbow color loading bar"""
    rainbow_colors = [colors.RED, colors.YELLOW, colors.GREEN, colors.CYAN, colors.SKY_BLUE, colors.MAGENTA]
    bar_length = 30
    for i in range(bar_length + 1):
        percent = int((i / bar_length) * 100)
        filled = '█' * i
        empty = '░' * (bar_length - i)
        color = rainbow_colors[i % len(rainbow_colors)]
        sys.stdout.write(f'\r{color}{text} [{filled}{empty}] {percent}%{colors.RESET}')
        sys.stdout.flush()
        time.sleep(duration / bar_length)
    print()

# ==========================================
# PROGRESS DOTS
# ==========================================

def progress_dots(text="Downloading", total=10, delay=0.3, color=colors.SKY_BLUE):
    """Simple progress dots animation"""
    for i in range(total + 1):
        dots = '.' * (i % 4)
        spaces = ' ' * (3 - len(dots))
        percent = int(i / total * 100) if total else 0
        sys.stdout.write(f'\r{color}{text}{dots}{spaces} {percent}%{colors.RESET}')
        sys.stdout.flush()
        time.sleep(delay)
    print()

