# ==========================================
# COUNTDOWN ANIMATION
# ==========================================

def countdown_animation(seconds=3, text="Starting in"):
    """Countdown animation"""
    for i in range(seconds, 0, -1):
        sys.stdout.write(f'\r{colors.GOLD}{text}: {i}{colors.RESET}')
        sys.stdout.flush()
        time.sleep(1)
    print()
    success_message("Go!")

